#include <bits/stdc++.h>
#define fr first
#define sc second
using namespace std;
typedef pair<int,int> pii;

const int N=55;
const double eps=1e-6;

struct Edge{
    int to;
    double val;
    bool operator<(Edge x)const{
        return val<x.val;
    }
};

int n,m,l,c,v,match[N*N];
pii en[N],d[N];
vector<Edge> e[N];
bool vis[N*N];
double dis[N][N];

bool dfs(int x,double t){
    for(auto [y,ds]:e[x]){
        if(ds>t)
            break;
        if(!vis[y]){
            vis[y]=1;
            if(!match[y] || dfs(match[y],t)){
                match[y]=x;
                return true;
            }
        }
    }
    return false;
}

bool check(double t){
    memset(match,0,sizeof(match));
    for(int i=1;i<=m;i++){
        memset(vis,0,sizeof(vis));
        if(!dfs(i,t))
            return false;
    }
    return true;
}

int main(){
    scanf("%d%d%d%d%d",&n,&m,&l,&c,&v);
    for(int i=1;i<=m;i++)
        scanf("%d%d",&en[i].fr,&en[i].sc);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&d[i].fr,&d[i].sc);
    for(int i=1;i<=m;i++){
        for(int j=1;j<=n;j++){
            dis[i][j]=sqrt((en[i].fr-d[j].fr)*(en[i].fr-d[j].fr)+(en[i].sc-d[j].sc)*(en[i].sc-d[j].sc));
            for(int k=1;k<=m;k++)
                e[i].push_back({(k-1)*n+j,1.0*dis[i][j]/v+l/60.0*k+c*(k-1)});
        }
        sort(e[i].begin(),e[i].end());
    }
    double l=0,r=1e9;
    while(l+eps<r){
        double mid=(l+r)/2;
        if(check(mid))
            r=mid;
        else
            l=mid;
    }
    printf("%.6lf",l);
    return 0;
}
